pragma solidity ^0.8.20;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { IERC1155 } from "@openzeppelin/contracts/token/ERC1155/IERC1155.sol";
import { IERC1155Receiver } from "@openzeppelin/contracts/token/ERC1155/IERC1155Receiver.sol";
import { ERC165 } from "@openzeppelin/contracts/utils/introspection/ERC165.sol";
import { IERC165 } from "@openzeppelin/contracts/utils/introspection/IERC165.sol";

/// @title CGDistribution — ERC-1155 token distribution to a beneficiary list
/// @notice Holds tokens of a specific ERC-1155 type and distributes them to beneficiaries.
///         Transitions: DRAFT → READY → DISTRIBUTED.
///         Implements IERC1155Receiver so it can receive tokens via safe transfers.
contract CGDistribution is Ownable, ERC165, IERC1155Receiver {
    enum State {
        DRAFT,
        READY,
        DISTRIBUTED
    }

    IERC1155 public immutable token;
    uint256 public immutable tokenId;

    address[] public beneficiaries;
    uint256[] public amounts;
    State public state;

    event BeneficiariesSet(uint256 count, uint256 totalAmount);
    event DistributionReady();
    event TokensDistributed(uint256 count, uint256 totalAmount);

    error NotInState(State expected, State actual);
    error ArrayLengthMismatch();
    error EmptyBeneficiaries();
    error InsufficientTokenBalance(uint256 required, uint256 available);
    error ZeroAmount();
    error ZeroAddress();
    error UnsupportedReceiver(address beneficiary);

    constructor(address owner_, IERC1155 token_, uint256 tokenId_) Ownable(owner_) {
        token = token_;
        tokenId = tokenId_;
        state = State.DRAFT;
    }

    /// @notice Set or replace the beneficiary list. Only when DRAFT.
    ///         For NFT-like distributions set each amount to 1; for fungible use any amount.
    function setBeneficiaries(address[] calldata beneficiaries_, uint256[] calldata amounts_) external onlyOwner {
        if (state != State.DRAFT) revert NotInState(State.DRAFT, state);
        if (beneficiaries_.length != amounts_.length) revert ArrayLengthMismatch();
        if (beneficiaries_.length == 0) revert EmptyBeneficiaries();

        for (uint256 i = 0; i < beneficiaries_.length; i++) {
            if (beneficiaries_[i] == address(0)) revert ZeroAddress();
            if (amounts_[i] == 0) revert ZeroAmount();
            _requireValidReceiver(beneficiaries_[i]);
        }

        beneficiaries = beneficiaries_;
        amounts = amounts_;

        emit BeneficiariesSet(beneficiaries_.length, totalRequired());
    }

    /// @notice Append new beneficiaries to the existing list. Only when DRAFT.
    function addBeneficiaries(address[] calldata newBeneficiaries_, uint256[] calldata newAmounts_) external onlyOwner {
        if (state != State.DRAFT) revert NotInState(State.DRAFT, state);
        if (newBeneficiaries_.length != newAmounts_.length) revert ArrayLengthMismatch();
        if (newBeneficiaries_.length == 0) revert EmptyBeneficiaries();

        for (uint256 i = 0; i < newBeneficiaries_.length; i++) {
            if (newBeneficiaries_[i] == address(0)) revert ZeroAddress();
            if (newAmounts_[i] == 0) revert ZeroAmount();
            _requireValidReceiver(newBeneficiaries_[i]);
            beneficiaries.push(newBeneficiaries_[i]);
            amounts.push(newAmounts_[i]);
        }

        emit BeneficiariesSet(beneficiaries.length, totalRequired());
    }

    /// @notice Remove beneficiaries by address. Silently skips addresses not in the list. Only when DRAFT.
    /// @dev O(n*m) where n = current list length and m = toRemove_ length. Acceptable for typical
    ///      charity distribution sizes; avoid very large arrays to stay within block gas limits.
    function removeBeneficiaries(address[] calldata toRemove_) external onlyOwner {
        if (state != State.DRAFT) revert NotInState(State.DRAFT, state);
        if (toRemove_.length == 0) revert EmptyBeneficiaries();

        for (uint256 r = 0; r < toRemove_.length; r++) {
            for (uint256 i = 0; i < beneficiaries.length; i++) {
                if (beneficiaries[i] == toRemove_[r]) {
                    uint256 last = beneficiaries.length - 1;
                    beneficiaries[i] = beneficiaries[last];
                    amounts[i] = amounts[last];
                    beneficiaries.pop();
                    amounts.pop();
                    break;
                }
            }
        }

        emit BeneficiariesSet(beneficiaries.length, beneficiaries.length > 0 ? totalRequired() : 0);
    }

    /// @notice Transition to READY. Requires the contract holds sufficient tokens.
    function markReady() external onlyOwner {
        if (state != State.DRAFT) revert NotInState(State.DRAFT, state);
        if (beneficiaries.length == 0) revert EmptyBeneficiaries();

        uint256 required = totalRequired();
        uint256 balance = token.balanceOf(address(this), tokenId);
        if (balance < required) revert InsufficientTokenBalance(required, balance);

        state = State.READY;
        emit DistributionReady();
    }

    /// @notice Transfer tokens to all beneficiaries. Transitions to DISTRIBUTED.
    function distribute() external onlyOwner {
        if (state != State.READY) revert NotInState(State.READY, state);

        uint256 total;
        for (uint256 i = 0; i < beneficiaries.length; i++) {
            token.safeTransferFrom(address(this), beneficiaries[i], tokenId, amounts[i], "");
            total += amounts[i];
        }

        state = State.DISTRIBUTED;
        emit TokensDistributed(beneficiaries.length, total);
    }

    /// @notice Total tokens required for all beneficiaries.
    function totalRequired() public view returns (uint256 total) {
        for (uint256 i = 0; i < amounts.length; i++) {
            total += amounts[i];
        }
    }

    function beneficiaryCount() external view returns (uint256) {
        return beneficiaries.length;
    }

    function getBeneficiaries() external view returns (address[] memory) {
        return beneficiaries;
    }

    function getAmounts() external view returns (uint256[] memory) {
        return amounts;
    }

    /// @dev EOAs always pass. Contracts must advertise IERC1155Receiver via ERC-165 so that
    ///      `safeTransferFrom` in `distribute()` cannot revert with `ERC1155InvalidReceiver`
    ///      after the distribution has been locked into READY.
    function _requireValidReceiver(address beneficiary) internal view {
        if (beneficiary.code.length == 0) return;
        try IERC165(beneficiary).supportsInterface(type(IERC1155Receiver).interfaceId) returns (bool ok) {
            if (!ok) revert UnsupportedReceiver(beneficiary);
        } catch {
            revert UnsupportedReceiver(beneficiary);
        }
    }

    // ── IERC1155Receiver ─────────────────────────────────────────────────────

    function onERC1155Received(
        address,
        address,
        uint256,
        uint256,
        bytes calldata
    ) external pure override returns (bytes4) {
        return this.onERC1155Received.selector;
    }

    function onERC1155BatchReceived(
        address,
        address,
        uint256[] calldata,
        uint256[] calldata,
        bytes calldata
    ) external pure override returns (bytes4) {
        return this.onERC1155BatchReceived.selector;
    }

    function supportsInterface(bytes4 interfaceId) public view override(ERC165, IERC165) returns (bool) {
        return interfaceId == type(IERC1155Receiver).interfaceId || super.supportsInterface(interfaceId);
    }
}
","keccak256":"0x6797b88c080c04fb0d9d067138338997c8c8b63816b7e8edc168cc9fc7dc4f21","license":"MIT"},"contracts/CGOrganization.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { CGProgramFactory } from "./CGProgramFactory.sol";

/// @title CGOrganization — Groups multiple CGPrograms under one owner
/// @notice Created by CGRegistry. The owner can create programs on demand via CGProgramFactory.
contract CGOrganization is Ownable {
    string public name;
    CGProgramFactory public immutable programFactory;
    address[] public programs;
    mapping(address => bool) public isProgram;

    event ProgramCreated(address indexed program, string name, bool lockDistributions);

    error EmptyName();

    constructor(address owner_, string memory name_, CGProgramFactory programFactory_) Ownable(owner_) {
        name = name_;
        programFactory = programFactory_;
    }

    /// @notice Deploy a new CGProgram owned by this organization's owner.
    function createProgram(string calldata name_, bool lockDistributions_) external onlyOwner returns (address) {
        if (bytes(name_).length == 0) revert EmptyName();
        address addr = programFactory.createProgram(owner(), name_, lockDistributions_);
        programs.push(addr);
        isProgram[addr] = true;

        emit ProgramCreated(addr, name_, lockDistributions_);
        return addr;
    }

    function programCount() external view returns (uint256) {
        return programs.length;
    }

    /// @notice Paginated read of program addresses.
    function getPrograms(uint256 offset, uint256 limit) external view returns (address[] memory) {
        uint256 len = programs.length;
        if (offset >= len) return new address[](0);

        uint256 end = offset + limit;
        if (end > len) end = len;
        uint256 size = end - offset;

        address[] memory result = new address[](size);
        for (uint256 i = 0; i < size; i++) {
            result[i] = programs[offset + i];
        }
        return result;
    }
}
","keccak256":"0xb72fd77e61afc1694eb8508150a3e61409eee22ff3cbfb8e07d750dcd032774a","license":"MIT"},"contracts/CGPaymaster.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { CGRegistry } from "./CGRegistry.sol";
import { CGOrganization } from "./CGOrganization.sol";

// ── Minimal ERC-4337 EntryPoint v0.6 interface ───────────────────────────────

interface IEntryPoint {
    struct DepositInfo {
        uint112 deposit;
        bool staked;
        uint112 stake;
        uint32 unstakeDelaySec;
        uint48 withdrawTime;
    }

    function depositTo(address account) external payable;
    function withdrawTo(address payable withdrawAddress, uint256 withdrawAmount) external;
    function getDepositInfo(address account) external view returns (DepositInfo memory);
    function balanceOf(address account) external view returns (uint256);
}

// ── ERC-4337 UserOperation struct (EntryPoint v0.6) ──────────────────────────

struct UserOperation {
    address sender;
    uint256 nonce;
    bytes initCode;
    bytes callData;
    uint256 callGasLimit;
    uint256 verificationGasLimit;
    uint256 preVerificationGas;
    uint256 maxFeePerGas;
    uint256 maxPriorityFeePerGas;
    bytes paymasterAndData;
    bytes signature;
}

enum PostOpMode {
    opSucceeded,
    opReverted,
    postOpReverted
}

// ─────────────────────────────────────────────────────────────────────────────

/// @title CGPaymaster — ERC-4337 Paymaster for Chain.Giving gas sponsorship
///
/// @notice Sponsors gas for beneficiary and organization owner UserOperations.
///         Each organization has an independent ETH budget tracked on-chain.
///         The total ETH is held at the EntryPoint under this paymaster's deposit;
///         per-org accounting is maintained in the `orgBalance` mapping.
///         Validation is fully on-chain — no off-chain relayer or signing service needed.
///
/// @dev    paymasterAndData layout:
///           [0  :20] — this paymaster address (set by wallet / bundler tooling)
///           [20 :40] — sponsoring org address (caller-supplied, 20 bytes)
///
///         Sponsored calls must use the standard execute(address,uint256,bytes) selector
///         (Coinbase Smart Wallet, ERC-4337 SimpleAccount, and most compatible wallets).
///         The resolved call target must belong to the sponsoring org — checked by walking
///         the on-chain ownership chain: org → program → token/distribution/crowdfunding.
///
/// @dev    Management model:
///           • By default the CGPaymaster owner (= CGRegistry deployer) manages every org's stash.
///           • An org can opt into self-management via `transferManagement`.
///           • Only the current manager may `withdraw` or re-`transferManagement` an org's budget.
contract CGPaymaster is Ownable {
    // ── Constants ─────────────────────────────────────────────────────────────

    /// @dev keccak256("execute(address,uint256,bytes)")[0:4]
    ///      Used by Coinbase Smart Wallet, ERC-4337 SimpleAccount, and most compatible wallets.
    bytes4 private constant EXECUTE_SELECTOR = bytes4(keccak256("execute(address,uint256,bytes)"));

    /// @dev Byte offset where the org address starts inside paymasterAndData.
    uint256 private constant ORG_DATA_OFFSET = 20;

    // ── State ─────────────────────────────────────────────────────────────────

    /// @notice The ERC-4337 EntryPoint singleton this paymaster is registered with.
    IEntryPoint public immutable entryPoint;

    /// @notice The Chain.Giving registry used to verify org and program addresses.
    CGRegistry public immutable registry;

    /// @notice Per-org internal gas budget (accounting only; actual ETH lives at EntryPoint).
    mapping(address org => uint256) public orgBalance;

    /// @notice Who may withdraw or reassign an org's budget.
    ///         address(0) means the CGPaymaster owner manages the org (default).
    mapping(address org => address) public orgManager;

    /// @notice Emit LowBalance when an org's remaining budget falls below this value (in wei).
    uint256 public lowBalanceThreshold;

    // ── Events ────────────────────────────────────────────────────────────────

    event Deposited(address indexed org, uint256 amount, address indexed depositor);
    event GasCharged(address indexed org, uint256 actualCost, uint256 remainingBalance);
    event LowBalance(address indexed org, uint256 balance);
    event Withdrawn(address indexed org, uint256 amount, address indexed to);
    event ManagementTransferred(address indexed org, address indexed newManager);
    event LowBalanceThresholdSet(uint256 threshold);

    // ── Errors ────────────────────────────────────────────────────────────────

    error OnlyEntryPoint();
    error NotOrgManager();
    error NotRegisteredOrg();
    error InsufficientOrgBalance(uint256 available, uint256 required);
    error InvalidCallTarget();
    error InvalidCallData();

    // ── Constructor ───────────────────────────────────────────────────────────

    constructor(IEntryPoint entryPoint_, CGRegistry registry_, uint256 lowBalanceThreshold_) Ownable(msg.sender) {
        entryPoint = entryPoint_;
        registry = registry_;
        lowBalanceThreshold = lowBalanceThreshold_;
    }

    // ── Modifiers ─────────────────────────────────────────────────────────────

    modifier onlyEntryPoint() {
        if (msg.sender != address(entryPoint)) revert OnlyEntryPoint();
        _;
    }

    // ── Funding ───────────────────────────────────────────────────────────────

    /// @notice Top up an org's gas budget. Sends ETH to the EntryPoint under this paymaster's deposit.
    ///         Callable by anyone — the registry owner tops up orgs as a managed service.
    /// @param org The CGOrganization address to credit.
    function depositFor(address org) external payable {
        if (!registry.isOrganization(org)) revert NotRegisteredOrg();
        orgBalance[org] += msg.value;
        entryPoint.depositTo{ value: msg.value }(address(this));
        emit Deposited(org, msg.value, msg.sender);
    }

    // ── Withdrawal ────────────────────────────────────────────────────────────

    /// @notice Withdraw unused ETH from an org's budget. Only callable by the org's manager.
    /// @param org    The CGOrganization whose budget to reduce.
    /// @param to     Recipient of the withdrawn ETH.
    /// @param amount Amount to withdraw in wei.
    function withdraw(address org, address payable to, uint256 amount) external {
        if (msg.sender != _managerOf(org)) revert NotOrgManager();
        if (orgBalance[org] < amount) revert InsufficientOrgBalance(orgBalance[org], amount);

        orgBalance[org] -= amount;
        entryPoint.withdrawTo(to, amount);
        emit Withdrawn(org, amount, to);
    }

    // ── Management ────────────────────────────────────────────────────────────

    /// @notice Hand over management of an org's gas budget to a new address.
    ///         Allows an org owner to self-manage their stash instead of relying on the registry owner.
    ///         Only the current manager may call this.
    /// @param org        The CGOrganization to reassign.
    /// @param newManager The new manager address. Use address(0) to revert to CGPaymaster owner.
    function transferManagement(address org, address newManager) external {
        if (msg.sender != _managerOf(org)) revert NotOrgManager();
        orgManager[org] = newManager;
        emit ManagementTransferred(org, newManager);
    }

    /// @notice Update the low-balance warning threshold. Only callable by the CGPaymaster owner.
    function setLowBalanceThreshold(uint256 threshold) external onlyOwner {
        lowBalanceThreshold = threshold;
        emit LowBalanceThresholdSet(threshold);
    }

    // ── ERC-4337 Paymaster interface ──────────────────────────────────────────

    /// @notice Called by the EntryPoint before UserOperation execution.
    ///         Validates the sponsoring org has sufficient budget and that the call targets
    ///         a contract owned by that org. Reserves the maximum possible gas cost.
    ///
    /// @param userOp     The UserOperation to validate.
    /// @param maxCost    Maximum ETH the EntryPoint may charge for this operation.
    /// @return context       Encoded (org, reserved) passed to postOp for settlement.
    /// @return validationData 0 = valid; SIG_VALIDATION_FAILED constant if invalid (not used here).
    function validatePaymasterUserOp(
        UserOperation calldata userOp,
        bytes32,
        uint256 maxCost
    ) external onlyEntryPoint returns (bytes memory context, uint256 validationData) {
        address org = address(bytes20(userOp.paymasterAndData[ORG_DATA_OFFSET:ORG_DATA_OFFSET + 20]));

        if (!registry.isOrganization(org)) revert NotRegisteredOrg();
        if (orgBalance[org] < maxCost) revert InsufficientOrgBalance(orgBalance[org], maxCost);
        if (!_isValidCall(userOp.callData, CGOrganization(org))) revert InvalidCallTarget();

        // Reserve the worst-case cost; postOp refunds the unused portion.
        orgBalance[org] -= maxCost;

        return (abi.encode(org, maxCost), 0);
    }

    /// @notice Called by the EntryPoint after UserOperation execution.
    ///         Refunds unused gas to the org's budget and emits monitoring events.
    ///
    /// @param context       Encoded (org, reserved) from validatePaymasterUserOp.
    /// @param actualGasCost Actual ETH charged by the EntryPoint for this operation.
    function postOp(PostOpMode, bytes calldata context, uint256 actualGasCost) external onlyEntryPoint {
        (address org, uint256 reserved) = abi.decode(context, (address, uint256));

        orgBalance[org] += reserved - actualGasCost;

        uint256 remaining = orgBalance[org];
        emit GasCharged(org, actualGasCost, remaining);

        if (remaining < lowBalanceThreshold) {
            emit LowBalance(org, remaining);
        }
    }

    // ── Views ─────────────────────────────────────────────────────────────────

    /// @notice Total ETH deposited at the EntryPoint under this paymaster's account.
    function totalDeposit() external view returns (uint256) {
        return entryPoint.balanceOf(address(this));
    }

    /// @notice Returns the effective manager for an org's budget.
    ///         Falls back to the CGPaymaster owner when no explicit manager is set.
    function managerOf(address org) external view returns (address) {
        return _managerOf(org);
    }

    // ── Internal ──────────────────────────────────────────────────────────────

    function _managerOf(address org) internal view returns (address) {
        address m = orgManager[org];
        return m == address(0) ? owner() : m;
    }

    /// @dev Validates callData encodes a standard execute(address,uint256,bytes) call
    ///      whose target belongs to the given org.
    function _isValidCall(bytes calldata callData, CGOrganization org) internal view returns (bool) {
        // Minimum length: 4-byte selector + 32-byte address + 32-byte uint256 = 68 bytes
        if (callData.length < 68) revert InvalidCallData();
        if (bytes4(callData[0:4]) != EXECUTE_SELECTOR) revert InvalidCallData();

        // ABI-decode target from the first 32-byte argument slot (address is right-aligned)
        address target = address(uint160(uint256(bytes32(callData[4:36]))));
        return _isOrgContract(org, target);
    }

    /// @dev Returns true if `target` is a contract that belongs to `org`:
    ///        - the org contract itself
    ///        - a CGProgram created by the org
    ///        - a CGToken, CGDistribution, or CGCrowdfunding owned by one of the org's programs
    ///          (all are Ownable with their parent CGProgram as owner)
    ///
    ///      The code-length guard is required before the try/catch: calling owner() on an EOA
    ///      succeeds at the EVM level (no code → empty return data), but Solidity's ABI decoder
    ///      then fails to decode zero bytes as address, and that decode error propagates outside
    ///      the catch block as an unhandled revert.
    function _isOrgContract(CGOrganization org, address target) internal view returns (bool) {
        if (target == address(org)) return true;
        if (org.isProgram(target)) return true;
        // Only attempt ownership lookup if target is a contract
        if (target.code.length == 0) return false;
        try Ownable(target).owner() returns (address parent) {
            return org.isProgram(parent);
        } catch {
            return false;
        }
    }
}
","keccak256":"0x49936ea2f97e6895eaadf1920bbdf24ec391c8bec9ce33c5f17f82731f1260f9","license":"MIT"},"contracts/CGProgram.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { IERC1155 } from "@openzeppelin/contracts/token/ERC1155/IERC1155.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { IERC20Permit } from "@openzeppelin/contracts/token/ERC20/extensions/IERC20Permit.sol";
import { SafeERC20 } from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import { CGToken } from "./CGToken.sol";
import { CGCrowdfunding } from "./CGCrowdfunding.sol";
import { CGDistribution } from "./CGDistribution.sol";
import { CGComponentFactory } from "./CGComponentFactory.sol";

/// @title CGProgram — Orchestrates crowdfunding and ERC-1155 token distributions
/// @notice Top-level contract tying one crowdfunding to one-or-more distributions.
///         Each distribution uses a specific token type from the shared CGToken contract.
///         Child contracts are deployed via external factories to keep bytecode under the
///         24 KB Spurious Dragon limit.
contract CGProgram is Ownable {
    using SafeERC20 for IERC20;

    enum State {
        ACTIVE,
        EXECUTING,
        COMPLETED,
        CANCELLED
    }

    struct TokenTypeInfo {
        uint256 tokenId;
        string name;
        string symbol;
        uint256 maxSupply;
        uint256 totalMinted;
        string uri;
        bool transferable;
        bool burnable;
    }

    struct CrowdfundingInfo {
        address addr;
        address currency;
        uint256 fundingTarget;
        uint256 deadline;
        CGCrowdfunding.State state;
        uint256 totalRaised;
        uint256 totalTracked;
        bool isFunded;
    }

    struct DistributionInfo {
        address addr;
        uint256 tokenId;
        CGDistribution.State state;
        uint256 beneficiaryCount;
        uint256 totalRequired;
        address[] beneficiaries;
        uint256[] amounts;
    }

    string public name;
    bool public immutable lockDistributions;
    CGComponentFactory public immutable componentFactory;
    CGToken public token;
    CGCrowdfunding public crowdfunding;
    CGDistribution[] public distributions;
    State public state;

    event ProgramCreated(string name, address token, bool lockDistributions);
    event TokenTypeDefined(
        uint256 indexed tokenId,
        string name,
        string symbol,
        uint256 maxSupply,
        bool transferable,
        bool burnable
    );
    event CrowdfundingSet(address crowdfunding, address currency);
    event DistributionCreated(uint256 index, address distribution, uint256 tokenId);
    event DistributionDeleted(uint256 index, address distribution);
    event ProgramExecuted();
    event ProgramCancelled();

    error ProgramNotActive();
    error CrowdfundingAlreadySet();
    error NoCrowdfunding();
    error NoDistributions();
    error DistributionNotReady(uint256 index);
    error DistributionsLocked();
    error ExceedsTotalSupply(uint256 tokenId, uint256 totalRequired, uint256 maxSupply);
    error DistributionAlreadyDistributed(uint256 index);
    error ContributionsExist();

    constructor(
        address owner_,
        string memory name_,
        bool lockDistributions_,
        CGComponentFactory componentFactory_
    ) Ownable(owner_) {
        name = name_;
        lockDistributions = lockDistributions_;
        componentFactory = componentFactory_;

        token = CGToken(componentFactory_.createToken(address(this)));
        state = State.ACTIVE;

        emit ProgramCreated(name_, address(token), lockDistributions_);
    }

    /// @notice Define a new ERC-1155 token type on the program's token contract.
    function defineTokenType(
        string calldata name_,
        string calldata symbol_,
        uint256 maxSupply_,
        string calldata uri_,
        bool transferable_,
        bool burnable_
    ) external onlyOwner returns (uint256 tokenId) {
        if (state != State.ACTIVE) revert ProgramNotActive();
        tokenId = token.defineTokenType(name_, symbol_, maxSupply_, uri_, transferable_, burnable_);
        emit TokenTypeDefined(tokenId, name_, symbol_, maxSupply_, transferable_, burnable_);
    }

    /// @notice Deploy and attach a CGCrowdfunding for the given ERC-20 currency.
    function setCrowdfunding(address currency_, uint256 target_, uint256 deadline_) external onlyOwner {
        if (state != State.ACTIVE) revert ProgramNotActive();
        if (address(crowdfunding) != address(0)) revert CrowdfundingAlreadySet();

        crowdfunding = CGCrowdfunding(
            componentFactory.createCrowdfunding(address(this), currency_, target_, deadline_)
        );
        emit CrowdfundingSet(address(crowdfunding), currency_);
    }

    /// @notice Deploy a new CGDistribution for a specific token type.
    function createDistribution(uint256 tokenId_) external onlyOwner returns (address) {
        if (state != State.ACTIVE) revert ProgramNotActive();
        if (lockDistributions && _crowdfundingHasContributions()) revert DistributionsLocked();

        // Validate the token type exists
        token.getTokenType(tokenId_);

        CGDistribution dist = CGDistribution(
            componentFactory.createDistribution(address(this), IERC1155(address(token)), tokenId_)
        );
        distributions.push(dist);

        // Allow the distribution contract to transfer soulbound tokens on behalf of the program.
        token.setAuthorizedTransferrer(address(dist), true);

        uint256 index = distributions.length - 1;
        emit DistributionCreated(index, address(dist), tokenId_);
        return address(dist);
    }

    function setBeneficiaries(
        uint256 distributionIndex,
        address[] calldata beneficiaries_,
        uint256[] calldata amounts_
    ) external onlyOwner {
        if (state != State.ACTIVE) revert ProgramNotActive();
        if (lockDistributions && _crowdfundingHasContributions()) revert DistributionsLocked();

        CGDistribution dist = distributions[distributionIndex];
        dist.setBeneficiaries(beneficiaries_, amounts_);
        _validateSupplyCap(dist.tokenId());
    }

    function addBeneficiaries(
        uint256 distributionIndex,
        address[] calldata beneficiaries_,
        uint256[] calldata amounts_
    ) external onlyOwner {
        if (state != State.ACTIVE) revert ProgramNotActive();
        if (lockDistributions && _crowdfundingHasContributions()) revert DistributionsLocked();

        CGDistribution dist = distributions[distributionIndex];
        dist.addBeneficiaries(beneficiaries_, amounts_);
        _validateSupplyCap(dist.tokenId());
    }

    function removeBeneficiaries(uint256 distributionIndex, address[] calldata toRemove_) external onlyOwner {
        if (state != State.ACTIVE) revert ProgramNotActive();
        if (lockDistributions && _crowdfundingHasContributions()) revert DistributionsLocked();

        distributions[distributionIndex].removeBeneficiaries(toRemove_);
    }

    function deleteDistribution(uint256 distributionIndex) external onlyOwner {
        if (state != State.ACTIVE) revert ProgramNotActive();
        CGDistribution.State distState = distributions[distributionIndex].state();
        if (distState == CGDistribution.State.DISTRIBUTED) revert DistributionAlreadyDistributed(distributionIndex);
        if (distState == CGDistribution.State.READY && _crowdfundingHasContributions()) revert ContributionsExist();

        address deleted = address(distributions[distributionIndex]);

        token.setAuthorizedTransferrer(deleted, false);

        uint256 last = distributions.length - 1;
        if (distributionIndex != last) {
            distributions[distributionIndex] = distributions[last];
        }
        distributions.pop();

        emit DistributionDeleted(distributionIndex, deleted);
    }

    function markDistributionReady(uint256 distributionIndex) external onlyOwner {
        if (state != State.ACTIVE) revert ProgramNotActive();

        CGDistribution dist = distributions[distributionIndex];
        uint256 required = dist.totalRequired();
        uint256 distTokenId = dist.tokenId();

        token.mint(address(dist), distTokenId, required);
        dist.markReady();
    }

    /// @notice Donate ERC-20 tokens through the program. Caller must approve the program for `amount`.
    ///         Enforces lock-distributions gating.
    function donate(uint256 amount) external {
        _preDonateChecks();
        IERC20 currency = crowdfunding.token();
        currency.safeTransferFrom(msg.sender, address(this), amount);
        currency.forceApprove(address(crowdfunding), amount);
        crowdfunding.donateFor(msg.sender, amount);
    }

    /// @notice EIP-2612 permit + donate in one transaction. Donor signs a permit authorizing
    ///         the PROGRAM (not the crowdfunding) to spend `amount`. Permit is wrapped in
    ///         try/catch to defend against permit-front-running griefing.
    function donateWithPermit(
        uint256 amount,
        uint256 permitDeadline,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) external {
        _preDonateChecks();
        IERC20 currency = crowdfunding.token();
        try IERC20Permit(address(currency)).permit(msg.sender, address(this), amount, permitDeadline, v, r, s) {} catch {}
        currency.safeTransferFrom(msg.sender, address(this), amount);
        currency.forceApprove(address(crowdfunding), amount);
        crowdfunding.donateFor(msg.sender, amount);
    }

    function _preDonateChecks() internal view {
        if (state != State.ACTIVE) revert ProgramNotActive();
        if (address(crowdfunding) == address(0)) revert NoCrowdfunding();

        if (lockDistributions) {
            if (distributions.length == 0) revert NoDistributions();
            for (uint256 i = 0; i < distributions.length; i++) {
                if (distributions[i].state() != CGDistribution.State.READY) revert DistributionNotReady(i);
            }
        }
    }

    /// @notice Withdraw funds and distribute tokens — all in one transaction.
    /// @dev    crowdfunding.withdraw() auto-syncs direct transfers and reverts with
    ///         NotInState if the campaign is still under target after sync.
    function execute() external onlyOwner {
        if (state != State.ACTIVE) revert ProgramNotActive();
        if (address(crowdfunding) == address(0)) revert NoCrowdfunding();
        if (distributions.length == 0) revert NoDistributions();

        for (uint256 i = 0; i < distributions.length; i++) {
            if (distributions[i].state() != CGDistribution.State.READY) revert DistributionNotReady(i);
        }

        // Act as a reentrancy guard: external calls below (withdraw, distribute)
        // will revert if they re-enter any function guarded by `ProgramNotActive`.
        state = State.EXECUTING;

        crowdfunding.withdraw(owner());

        for (uint256 i = 0; i < distributions.length; i++) {
            distributions[i].distribute();
        }

        state = State.COMPLETED;
        emit ProgramExecuted();
    }

    /// @notice Owner-only wrapper around crowdfunding.returnUntracked(to, amount).
    ///         Lets the program owner refund stray direct transfers identified off-chain.
    function returnUntracked(address to, uint256 amount) external onlyOwner {
        if (address(crowdfunding) == address(0)) revert NoCrowdfunding();
        crowdfunding.returnUntracked(to, amount);
    }

    /// @notice Owner-only wrapper around crowdfunding.sweepUntracked(to). Only callable
    ///         after the crowdfunding has been cancelled (enforced by the crowdfunding).
    function sweepUntracked(address to) external onlyOwner {
        if (address(crowdfunding) == address(0)) revert NoCrowdfunding();
        crowdfunding.sweepUntracked(to);
    }

    function cancel() external onlyOwner {
        if (state != State.ACTIVE) revert ProgramNotActive();

        state = State.CANCELLED;

        if (address(crowdfunding) != address(0) && crowdfunding.state() == CGCrowdfunding.State.ACTIVE) {
            crowdfunding.cancel();
        }

        emit ProgramCancelled();
    }

    function distributionCount() external view returns (uint256) {
        return distributions.length;
    }

    function getTokenTypes() external view returns (TokenTypeInfo[] memory infos) {
        uint256 count = token.nextTokenId();
        infos = new TokenTypeInfo[](count);
        for (uint256 i = 0; i < count; i++) {
            CGToken.TokenType memory tt = token.getTokenType(i);
            infos[i] = TokenTypeInfo({
                tokenId: i,
                name: tt.name,
                symbol: tt.symbol,
                maxSupply: tt.maxSupply,
                totalMinted: tt.totalMinted,
                uri: token.uri(i),
                transferable: tt.transferable,
                burnable: tt.burnable
            });
        }
    }

    function getCrowdfundingInfo() external view returns (CrowdfundingInfo memory info) {
        if (address(crowdfunding) == address(0)) return info;

        info = CrowdfundingInfo({
            addr: address(crowdfunding),
            currency: address(crowdfunding.token()),
            fundingTarget: crowdfunding.fundingTarget(),
            deadline: crowdfunding.deadline(),
            state: crowdfunding.state(),
            totalRaised: crowdfunding.totalRaised(),
            totalTracked: crowdfunding.totalTracked(),
            isFunded: crowdfunding.isFunded()
        });
    }

    function getDistributionInfo(uint256 index) public view returns (DistributionInfo memory) {
        CGDistribution dist = distributions[index];
        return
            DistributionInfo({
                addr: address(dist),
                tokenId: dist.tokenId(),
                state: dist.state(),
                beneficiaryCount: dist.beneficiaryCount(),
                totalRequired: dist.totalRequired(),
                beneficiaries: dist.getBeneficiaries(),
                amounts: dist.getAmounts()
            });
    }

    function getAllDistributionsInfo() external view returns (DistributionInfo[] memory infos) {
        infos = new DistributionInfo[](distributions.length);
        for (uint256 i = 0; i < distributions.length; i++) {
            infos[i] = getDistributionInfo(i);
        }
    }

    function _validateSupplyCap(uint256 distTokenId_) internal view {
        CGToken.TokenType memory tt = token.getTokenType(distTokenId_);
        if (tt.maxSupply > 0) {
            uint256 aggregateRequired = _totalRequiredForToken(distTokenId_);
            if (aggregateRequired > tt.maxSupply)
                revert ExceedsTotalSupply(distTokenId_, aggregateRequired, tt.maxSupply);
        }
    }

    function _crowdfundingHasContributions() internal view returns (bool) {
        return address(crowdfunding) != address(0) && crowdfunding.totalRaised() > 0;
    }

    function _totalRequiredForToken(uint256 tokenId_) internal view returns (uint256 total) {
        for (uint256 i = 0; i < distributions.length; i++) {
            CGDistribution dist = distributions[i];
            if (dist.tokenId() == tokenId_) {
                total += dist.totalRequired();
            }
        }
    }
}
