pragma solidity ^0.8.20;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { CGProgram } from "./CGProgram.sol";
import { CGComponentFactory } from "./CGComponentFactory.sol";

/// @title CGProgramFactory — Deploys CGProgram instances
/// @notice Only authorized callers (CGOrganizations created via CGRegistry) can use createProgram.
///         Ownership should be transferred to CGRegistry after deployment.
///         A shared CGComponentFactory is injected so CGProgram never uses `new` directly,
///         keeping every contract under the 24 KB Spurious Dragon limit.
contract CGProgramFactory is Ownable {
    CGComponentFactory public immutable componentFactory;

    mapping(address => bool) public authorizedCallers;

    event ProgramDeployed(address indexed program, address indexed owner, string name);
    event CallerAuthorized(address indexed caller, bool authorized);

    error Unauthorized();

    constructor(CGComponentFactory componentFactory_) Ownable(msg.sender) {
        componentFactory = componentFactory_;
    }

    /// @notice Authorize or deauthorize a caller (e.g. a CGOrganization). Only callable by owner (CGRegistry).
    function authorizeCaller(address caller_, bool authorized_) external onlyOwner {
        authorizedCallers[caller_] = authorized_;
        emit CallerAuthorized(caller_, authorized_);
    }

    /// @notice Deploy a new CGProgram. Only callable by authorized callers.
    function createProgram(address owner_, string calldata name_, bool lockDistributions_) external returns (address) {
        if (!authorizedCallers[msg.sender]) revert Unauthorized();
        CGProgram program = new CGProgram(owner_, name_, lockDistributions_, componentFactory);
        address addr = address(program);
        emit ProgramDeployed(addr, owner_, name_);
        return addr;
    }
}
","keccak256":"0x7555008b60dfceac17ac7881136168c7a568e50b4d36f75e6ce3bc5b248763ca","license":"MIT"},"contracts/CGRegistry.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { CGOrganization } from "./CGOrganization.sol";
import { CGProgramFactory } from "./CGProgramFactory.sol";

/// @title CGRegistry — Directory of all CGOrganization instances
/// @notice Only the registry owner (deployer) can create organizations.
contract CGRegistry is Ownable {
    CGProgramFactory public immutable programFactory;
    address[] public organizations;
    mapping(address => bool) public isOrganization;

    event OrganizationCreated(address indexed organization, address indexed owner, string name);
    event OrganizationAdded(address indexed organization);
    event OrganizationRemoved(address indexed organization);

    error EmptyName();
    error ZeroAddress();
    error NotOrganization();
    error AlreadyOrganization();

    constructor(CGProgramFactory programFactory_) Ownable(msg.sender) {
        programFactory = programFactory_;
    }

    /// @notice Deploy a new CGOrganization with the given owner. Only callable by registry owner.
    function createOrganization(string calldata name_, address owner_) external onlyOwner returns (address) {
        if (bytes(name_).length == 0) revert EmptyName();
        if (owner_ == address(0)) revert ZeroAddress();

        CGOrganization org = new CGOrganization(owner_, name_, programFactory);
        address addr = address(org);
        organizations.push(addr);
        isOrganization[addr] = true;

        // Authorize the new organization to use the factory
        programFactory.authorizeCaller(addr, true);

        emit OrganizationCreated(addr, owner_, name_);
        return addr;
    }

    /// @notice Add an existing CGOrganization by address (e.g. to re-add a previously removed org).
    ///         Only callable by registry owner. Re-authorizes the org to use the program factory.
    function addOrganization(address organization_) external onlyOwner {
        if (organization_ == address(0)) revert ZeroAddress();
        if (isOrganization[organization_]) revert AlreadyOrganization();

        organizations.push(organization_);
        isOrganization[organization_] = true;
        programFactory.authorizeCaller(organization_, true);

        emit OrganizationAdded(organization_);
    }

    /// @notice Remove an organization from the registry. Only callable by registry owner.
    /// @dev Revokes the organization's authorization to use the program factory. Does not
    ///      affect already-deployed programs owned by that organization.
    function removeOrganization(address organization_) external onlyOwner {
        if (!isOrganization[organization_]) revert NotOrganization();

        uint256 len = organizations.length;
        for (uint256 i = 0; i < len; i++) {
            if (organizations[i] == organization_) {
                if (i != len - 1) organizations[i] = organizations[len - 1];
                organizations.pop();
                break;
            }
        }

        delete isOrganization[organization_];
        programFactory.authorizeCaller(organization_, false);

        emit OrganizationRemoved(organization_);
    }

    function organizationCount() external view returns (uint256) {
        return organizations.length;
    }

    /// @notice Paginated read of organization addresses.
    function getOrganizations(uint256 offset, uint256 limit) external view returns (address[] memory) {
        uint256 len = organizations.length;
        if (offset >= len) return new address[](0);

        uint256 end = offset + limit;
        if (end > len) end = len;
        uint256 size = end - offset;

        address[] memory result = new address[](size);
        for (uint256 i = 0; i < size; i++) {
            result[i] = organizations[offset + i];
        }
        return result;
    }
}
","keccak256":"0x48d87d2953e4663439d5c1695e64b75e441951a26222c3f5991f301ce5081175","license":"MIT"},"contracts/CGToken.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { ERC1155 } from "@openzeppelin/contracts/token/ERC1155/ERC1155.sol";
import { ERC1155Burnable } from "@openzeppelin/contracts/token/ERC1155/extensions/ERC1155Burnable.sol";
import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";

/// @title CGToken — ERC-1155 multi-token for a Chain.Giving program
/// @notice One deployment per program. Supports multiple token types in a single contract.
///         Each type is configured independently: unlimited supply (fungible), capped supply
///         (semi-fungible badges), or supply of 1 (unique NFT). Owner (typically CGProgram)
///         controls type definition and minting. Each type can independently enable/disable
///         user transfers and burns.
contract CGToken is ERC1155Burnable, Ownable {
    struct TokenType {
        string name;
        string symbol;
        uint256 maxSupply; // 0 = unlimited; 1 = unique NFT; N = capped semi-fungible
        uint256 totalMinted;
        bool transferable; // true = holders can transfer; false = soulbound (owner can always transfer)
        bool burnable; // true = holders can burn; false = burn disabled (owner can always burn)
    }

    mapping(uint256 => TokenType) public tokenTypes;
    mapping(uint256 => string) private _uris;
    mapping(address => bool) public authorizedTransferrers;
    uint256 public nextTokenId;

    event TokenTypeDefined(
        uint256 indexed tokenId,
        string name,
        string symbol,
        uint256 maxSupply,
        bool transferable,
        bool burnable
    );
    event AuthorizedTransferrerSet(address indexed account, bool authorized);

    error UnknownTokenType(uint256 tokenId);
    error ExceedsMaxSupply(uint256 tokenId, uint256 requested, uint256 remaining);
    error TransferDisabled(uint256 tokenId);
    error BurnDisabled(uint256 tokenId);

    constructor(address owner_) ERC1155("") Ownable(owner_) {}

    /// @notice Grant or revoke an address's ability to bypass soulbound restrictions.
    ///         Used to allow CGDistribution contracts to transfer non-transferable tokens.
    function setAuthorizedTransferrer(address account, bool authorized) external onlyOwner {
        authorizedTransferrers[account] = authorized;
        emit AuthorizedTransferrerSet(account, authorized);
    }

    /// @notice Define a new token type. Returns the auto-assigned tokenId (starts at 0).
    /// @param name_         Display name (e.g. "Food Voucher")
    /// @param symbol_       Short symbol (e.g. "FOOD")
    /// @param maxSupply_    Hard cap on total minted. 0 = unlimited (fungible), 1 = unique NFT,
    ///                      N = capped supply (badges, tickets, etc.)
    /// @param uri_          Optional per-type metadata URI; falls back to contract-level URI if empty
    /// @param transferable_ Whether holders can transfer tokens (owner/program can always transfer)
    /// @param burnable_     Whether holders can burn tokens (owner/program can always burn)
    function defineTokenType(
        string calldata name_,
        string calldata symbol_,
        uint256 maxSupply_,
        string calldata uri_,
        bool transferable_,
        bool burnable_
    ) external onlyOwner returns (uint256 tokenId) {
        tokenId = nextTokenId++;
        tokenTypes[tokenId] = TokenType({
            name: name_,
            symbol: symbol_,
            maxSupply: maxSupply_,
            totalMinted: 0,
            transferable: transferable_,
            burnable: burnable_
        });
        if (bytes(uri_).length > 0) {
            _uris[tokenId] = uri_;
        }
        emit TokenTypeDefined(tokenId, name_, symbol_, maxSupply_, transferable_, burnable_);
    }

    /// @notice Mint tokens of a given type to a recipient. onlyOwner.
    function mint(address to, uint256 tokenId, uint256 amount) external onlyOwner {
        _validateMint(tokenId, amount);
        tokenTypes[tokenId].totalMinted += amount;
        _mint(to, tokenId, amount, "");
    }

    /// @notice Batch mint multiple token types in one call. onlyOwner.
    function mintBatch(address to, uint256[] calldata tokenIds, uint256[] calldata amounts) external onlyOwner {
        for (uint256 i = 0; i < tokenIds.length; i++) {
            _validateMint(tokenIds[i], amounts[i]);
            tokenTypes[tokenIds[i]].totalMinted += amounts[i];
        }
        _mintBatch(to, tokenIds, amounts, "");
    }

    /// @notice Per-type metadata URI; falls back to contract-level URI if none set.
    function uri(uint256 tokenId) public view override returns (string memory) {
        string memory tokenUri = _uris[tokenId];
        if (bytes(tokenUri).length > 0) return tokenUri;
        return super.uri(tokenId);
    }

    /// @notice Return full metadata for a token type.
    function getTokenType(uint256 tokenId) external view returns (TokenType memory) {
        if (tokenId >= nextTokenId) revert UnknownTokenType(tokenId);
        return tokenTypes[tokenId];
    }

    // ── Internal ─────────────────────────────────────────────────────────────

    function _validateMint(uint256 tokenId, uint256 amount) internal view {
        if (tokenId >= nextTokenId) revert UnknownTokenType(tokenId);
        TokenType storage tt = tokenTypes[tokenId];
        if (tt.maxSupply > 0 && tt.totalMinted + amount > tt.maxSupply)
            revert ExceedsMaxSupply(tokenId, amount, tt.maxSupply - tt.totalMinted);
    }

    /// @dev Enforce per-type transfer and burn restrictions.
    ///      Mints (from == 0) are always allowed (gated by onlyOwner on mint()).
    ///      The contract owner (CGProgram) and authorized transferrers (e.g. CGDistribution)
    ///      are always allowed to transfer and burn regardless of the flags.
    function _update(address from, address to, uint256[] memory ids, uint256[] memory values) internal override {
        bool isMint = from == address(0);
        bool isPrivileged = _msgSender() == owner() || authorizedTransferrers[_msgSender()];

        if (!isMint && !isPrivileged) {
            bool isBurn = to == address(0);
            for (uint256 i = 0; i < ids.length; i++) {
                if (ids[i] >= nextTokenId) revert UnknownTokenType(ids[i]);
                TokenType storage tt = tokenTypes[ids[i]];
                if (isBurn) {
                    if (!tt.burnable) revert BurnDisabled(ids[i]);
                } else {
                    if (!tt.transferable) revert TransferDisabled(ids[i]);
                }
            }
        }

        super._update(from, to, ids, values);
    }
}
